function preencherCamposComParametrosGET() {
    function getParametroGET(nome) {
        const urlParams = new URLSearchParams(window.location.search);
        return urlParams.get(nome);
    }
    const mapeamento = {
        'utm_source': 'field[1]',
        'utm_campaign': 'field[2]',
        'utm_term': 'field[3]',
        'utm_content': 'field[4]',
        'utm_medium': 'field[5]'
    };

    Object.entries(mapeamento).forEach(([parametro, campo]) => {
        const valor = getParametroGET(parametro);
        if (valor) { // Se o parâmetro existir na URL
            const elemento = document.getElementsByName(campo)[0];
            if (elemento) { // Se o campo existir no formulário
                elemento.value = valor;
            }
        }
    });
}
